import React from 'react';
import { Redirect, Route, Switch } from 'react-router-dom';
import { HomePage } from '../HomePage';
import { ArticlesPage } from '../ArticlesPage';
import './Main.scss';

export const Main = () => (
  <div className="Main">
    <Switch>
      <Route path="/h" exact>
        <HomePage />
      </Route>
      <Route path="/articles">
        <ArticlesPage />
      </Route>
      <Redirect path="/" to="/home" />
    </Switch>
  </div>
);
